from contextlib import contextmanager

@contextmanager
def suppress_errors(*exc_types):
    try:
        yield
    except exc_types:
        pass  # swallow listed types; everything else propagates

from collections import defaultdict

def total_by_dept(records):
    totals = defaultdict(int)
    for r in records:
        totals[r['dept']] += r['salary']
    return dict(totals)
